  queryClient: QueryClient;
  createShotWithGenerations: (input: {
    projectId: string;
    shotName: string;
    generationIds: string[];
  }) => Promise<CreateShotWithGenerationsRpcResult>;
}

export interface CreateShotWithGenerationsPathInput {
  selectedProjectId: string;
  shotName: string;
  generationIds: string[];
  queryClient: QueryClient;
  createShotWithGenerations: (input: {
    projectId: string;
    shotName: string;
    generationIds: string[];
  }) => Promise<CreateShotWithGenerationsRpcResult>;
