import type { Json } from '@/integrations/supabase/jsonTypes';
import type { GenerationRow } from '@/domains/generation/types';
import type { GenerationRowDto } from '@/domains/generation/types/generationRowDto';
import { asRecord, asNullableString, asNullableNumber } from '@/shared/lib/typeCoercion';

function asJsonRecord(value: unknown): Json | null | undefined {
  if (value === null) {
    return null;
  }
  return asRecord(value) as Json | null;
}

export function coerceGenerationRowDto(
  value: unknown,
): (GenerationRowDto & { params?: Json | null }) | null {
  const record = asRecord(value);
  if (!record || typeof record.id !== 'string') {
    return null;
  }

  return {
    id: record.id,
    ...(typeof record.generation_id === 'string' ? { generation_id: record.generation_id } : {}),
    ...(asNullableString(record.location) !== undefined ? { location: asNullableString(record.location) } : {}),
    ...(asNullableString(record.thumbnail_url) !== undefined ? { thumbnail_url: asNullableString(record.thumbnail_url) } : {}),
    ...(asNullableString(record.type) !== undefined ? { type: asNullableString(record.type) } : {}),
    ...(typeof record.createdAt === 'string' ? { createdAt: record.createdAt } : {}),
    ...(typeof record.created_at === 'string' ? { created_at: record.created_at } : {}),
    ...(asJsonRecord(record.metadata) !== undefined ? { metadata: asJsonRecord(record.metadata) } : {}),
    ...(asNullableString(record.name) !== undefined ? { name: asNullableString(record.name) } : {}),
    ...(asNullableNumber(record.timeline_frame) !== undefined ? { timeline_frame: asNullableNumber(record.timeline_frame) } : {}),
    ...(typeof record.starred === 'boolean' ? { starred: record.starred } : {}),
    ...(asNullableString(record.based_on) !== undefined ? { based_on: asNullableString(record.based_on) } : {}),
    ...(asJsonRecord(record.params) !== undefined ? { params: asJsonRecord(record.params) } : {}),
    ...(asNullableString(record.parent_generation_id) !== undefined ? { parent_generation_id: asNullableString(record.parent_generation_id) } : {}),
    ...(typeof record.is_child === 'boolean' ? { is_child: record.is_child } : {}),
    ...(asNullableNumber(record.child_order) !== undefined ? { child_order: asNullableNumber(record.child_order) } : {}),
    ...(asNullableString(record.pair_shot_generation_id) !== undefined ? { pair_shot_generation_id: asNullableString(record.pair_shot_generation_id) } : {}),
    ...(asNullableString(record.primary_variant_id) !== undefined ? { primary_variant_id: asNullableString(record.primary_variant_id) } : {}),
    ...(asNullableString(record.source_task_id) !== undefined ? { source_task_id: asNullableString(record.source_task_id) } : {}),
  } satisfies GenerationRowDto & { params?: Json | null };
}

export function mapGenerationRowDtoToRow(
  dto: GenerationRowDto & { params?: Json | null },
): GenerationRow {
  return {
    id: dto.id,
    generation_id: dto.generation_id,
    location: dto.location ?? null,
    imageUrl: dto.location ?? undefined,
    thumbUrl: dto.thumbnail_url ?? dto.location ?? undefined,
    type: dto.type ?? null,
    createdAt: dto.createdAt ?? dto.created_at,
    metadata: dto.metadata ?? null,
    name: dto.name ?? null,
    timeline_frame: dto.timeline_frame ?? null,
    starred: dto.starred,
    based_on: dto.based_on ?? null,
    params: (dto.params ?? undefined) as GenerationRow['params'],
    parent_generation_id: dto.parent_generation_id ?? null,
    is_child: dto.is_child,
    child_order: dto.child_order ?? null,
    pair_shot_generation_id: dto.pair_shot_generation_id ?? null,
    primary_variant_id: dto.primary_variant_id ?? null,
    source_task_id: dto.source_task_id ?? null,
  };
}

import type { InvalidateQueryFilters, QueryClient, QueryKey } from '@tanstack/react-query';
import { Shot, GenerationRow } from '@/domains/generation/types';
import { queryKeys } from '@/shared/lib/queryKeys';

function getShotsProjectPrefix(projectId: string): readonly QueryKey {
  return [...queryKeys.shots.all, projectId] as const;
}

function getShotListQueries(queryClient: QueryClient, projectId: string) {
  return queryClient.getQueriesData<Shot[]>({
    queryKey: getShotsProjectPrefix(projectId),
  });
}

/**
 * @param onlyExisting - If true, only update caches that already exist.
 *                       If false (default), will create cache entries if needed.
 */
export function updateAllShotsCaches(
  queryClient: QueryClient,
  projectId: string,
  updater: (old: Shot[] | undefined) => Shot[],
  onlyExisting: boolean = false
): void {
  const cachedQueries = getShotListQueries(queryClient, projectId);
  if (cachedQueries.length === 0) {
    if (!onlyExisting) {
      queryClient.setQueryData<Shot[]>(
        queryKeys.shots.list(projectId, 0),
        (old) => updater(old)
      );
    }
    return;
  }

  cachedQueries.forEach(([key, existing]) => {
    if (onlyExisting && existing === undefined) {
      return;
    }
    queryClient.setQueryData<Shot[]>(key, (old) => updater(old));
  });
}

export function rollbackShotsCaches(
  queryClient: QueryClient,
  projectId: string,
  previous: Shot[] | undefined
): void {
  if (!previous) return;
  const cachedQueries = getShotListQueries(queryClient, projectId);
  if (cachedQueries.length === 0) {
    queryClient.setQueryData(queryKeys.shots.list(projectId, 0), previous);
    return;
  }

  cachedQueries.forEach(([key]) => {
    queryClient.setQueryData(key, previous);
  });
}

export async function cancelShotsQueries(
  queryClient: QueryClient,
  projectId: string
): Promise<void> {
  await queryClient.cancelQueries({ queryKey: getShotsProjectPrefix(projectId) });
}

export function invalidateShotsQueries(
  queryClient: QueryClient,
  projectId: string,
  filters: Omit<InvalidateQueryFilters, 'queryKey'> = {},
): void {
  queryClient.invalidateQueries({
    queryKey: [...queryKeys.shots.all, projectId],
    ...filters,
  });
}

export function findShotsCache(
  queryClient: QueryClient,
  projectId: string
): Shot[] | undefined {
  const cachedQueries = getShotListQueries(queryClient, projectId);
  for (const [, data] of cachedQueries) {
    if (data && data.length > 0) {
      return data;
    }
  }
  for (const [, data] of cachedQueries) {
    if (data !== undefined) {
      return data;
    }
  }
  return undefined;
}

export function upsertShotInCache(
  queryClient: QueryClient,
  projectId: string,
  shot: Shot
): void {
  const shotPosition = shot.position ?? Number.MAX_SAFE_INTEGER;

  updateAllShotsCaches(queryClient, projectId, (oldShots = []) => {
    const remainingShots = oldShots.filter((existingShot) => existingShot.id !== shot.id);
    const insertionIndex = remainingShots.findIndex(
      (existingShot) => (existingShot.position ?? Number.MAX_SAFE_INTEGER) > shotPosition
    );

    if (insertionIndex === -1) {
      return [...remainingShots, shot];
    }

    const updatedShots = [...remainingShots];
    updatedShots.splice(insertionIndex, 0, shot);
    return updatedShots;
  });

  queryClient.setQueryData(queryKeys.shots.detail(shot.id), shot);
}

export function rollbackShotGenerationsCache(
  queryClient: QueryClient,
  shotId: string,
  previous: GenerationRow[] | undefined
): void {
  if (!previous) return;
  queryClient.setQueryData(queryKeys.generations.byShot(shotId), previous);
}

export async function cancelShotGenerationsQuery(
  queryClient: QueryClient,
  shotId: string
): Promise<void> {
  await queryClient.cancelQueries({ queryKey: queryKeys.generations.byShot(shotId) });
}

