import { QueryClient } from '@tanstack/react-query';
import { describe, expect, it } from 'vitest';
import { shotQueryKeys } from '@/shared/lib/queryKeys/shots';
import { applyAtomicShotCacheUpdate } from './shotCacheUpdate';

describe('applyAtomicShotCacheUpdate', () => {
  it('adds an optimistic shot to the list caches and initializes the detail cache', () => {
    const queryClient = new QueryClient();
    const existingShots = [
      {
        id: 'shot-1',
        name: 'Shot 1',
        images: [],
        project_id: 'project-1',
        position: 4,
        created_at: '2026-03-11T00:00:00.000Z',
      },
    ] as never;

    queryClient.setQueryData(shotQueryKeys.list('project-1', 0), existingShots);
    queryClient.setQueryData(shotQueryKeys.list('project-1', 5), existingShots);
    queryClient.setQueryData([...shotQueryKeys.all, 'project-1'], existingShots);

    applyAtomicShotCacheUpdate({
      selectedProjectId: 'project-1',
      shotId: 'shot-2',
      shotName: 'Shot 2',
      shotGenerationId: 'shot-gen-2',
      generationId: 'generation-2',
      generationPreview: {
        imageUrl: 'image.png',
        thumbUrl: 'thumb.png',
        type: 'image',
        location: 'storage/image.png',
      },
      shots: existingShots,
      queryClient,
    });

    const updatedList = queryClient.getQueryData(shotQueryKeys.list('project-1', 0)) as Array<Record<string, unknown>>;
    const detail = queryClient.getQueryData(shotQueryKeys.detail('shot-2')) as Record<string, unknown>;

    expect(updatedList).toHaveLength(2);
    expect(updatedList[1]).toEqual(
      expect.objectContaining({
        id: 'shot-2',
        name: 'Shot 2',
        project_id: 'project-1',
        position: 5,
      }),
    );
    expect((updatedList[1].images as Array<Record<string, unknown>>)[0]).toEqual(
      expect.objectContaining({
        id: 'shot-gen-2',
        generation_id: 'generation-2',
        imageUrl: 'image.png',
        thumbUrl: 'thumb.png',
        isOptimistic: true,
      }),
    );
    expect(detail).toEqual(
      expect.objectContaining({
        id: 'shot-2',
        name: 'Shot 2',
        project_id: 'project-1',
      }),
    );
  });

  it('leaves list caches unchanged when the shot already exists', () => {
    const queryClient = new QueryClient();
    const existingShots = [
      {
        id: 'shot-2',
        name: 'Shot 2',
        images: [],
        project_id: 'project-1',
        position: 2,
        created_at: '2026-03-11T00:00:00.000Z',
      },
    ] as never;

    queryClient.setQueryData(shotQueryKeys.list('project-1', 0), existingShots);

    applyAtomicShotCacheUpdate({
      selectedProjectId: 'project-1',
      shotId: 'shot-2',
      shotName: 'Shot 2',
      shotGenerationId: 'shot-gen-2',
      generationId: 'generation-2',
      shots: existingShots,
      queryClient,
    });

    const updatedList = queryClient.getQueryData(shotQueryKeys.list('project-1', 0));
    expect(updatedList).toBe(existingShots);
  });
});

/**
 * Composite shot creation operations.
 * These combine multiple operations (upload, create, add) into unified workflows.
 */

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { toast } from '@/shared/components/ui/runtime/sonner';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { enqueueGenerationsInvalidation } from '@/shared/hooks/invalidation/useGenerationInvalidation';
import { queryKeys } from '@/shared/lib/queryKeys';
import { useCreateShot } from './useShotsCrud';
import { useAddImageToShot } from './useShotGenerationMutations';
import { processDroppedImages, type ExternalImageDropVariables } from './externalImageDrop';
import type { CreateShotWithGenerationsRpcResult } from '@/shared/hooks/shotCreation/shotCreationTypes';

interface CreateShotWithImageResponse {
  shot_id: string;
  shot_name: string;
  shot_generation_id: string;
  success: boolean;
}

export const useCreateShotWithImage = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      projectId,
      shotName,
      generationId,
    }: {
      projectId: string;
      shotName: string;
      generationId: string;
    }) => {
      const { data, error } = await supabase().rpc('create_shot_with_image', {
          p_project_id: projectId,
          p_shot_name: shotName,
          p_generation_id: generationId,
        })
        .single();

      if (error) {
        throw error;
      }

      const typedData = data as CreateShotWithImageResponse;
      if (!typedData?.success) {
        throw new Error('Failed to create shot with image');
      }

      return {
        shotId: typedData.shot_id,
        shotName: typedData.shot_name,
        shotGenerationId: typedData.shot_generation_id,
      };
    },

    onSuccess: (data, variables) => {
      queryClient.invalidateQueries({
        queryKey: [...queryKeys.shots.all, variables.projectId],
        refetchType: 'inactive',
      });
      queryClient.invalidateQueries({
        queryKey: queryKeys.unified.projectPrefix(variables.projectId),
        refetchType: 'inactive',
      });

      if (data.shotId) {
        enqueueGenerationsInvalidation(queryClient, data.shotId, {
          reason: 'create-shot-with-image',
          scope: 'all',
          delayMs: 100,
        });
      }
    },

    onError: (error: Error) => {
      normalizeAndPresentError(error, { context: 'useShotCreation', toastTitle: 'Failed to create shot with image' });
    },
  });
};

export const useCreateShotWithGenerations = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      projectId,
      shotName,
      generationIds,
    }: {
      projectId: string;
      shotName: string;
      generationIds: string[];
    }) => {
      const { data, error } = await supabase().rpc('create_shot_with_generations', {
          p_project_id: projectId,
          p_shot_name: shotName,
          p_generation_ids: generationIds,
        })
        .single();

      if (error) {
        throw error;
      }

      const typedData = data as CreateShotWithGenerationsRpcResult | null;
      if (!typedData?.success) {
        throw new Error('Failed to create shot with generations');
      }

      return typedData;
    },

    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({
        queryKey: [...queryKeys.shots.all, variables.projectId],
        refetchType: 'inactive',
      });
      queryClient.invalidateQueries({
        queryKey: queryKeys.unified.projectPrefix(variables.projectId),
        refetchType: 'inactive',
      });
    },

    onError: (error: Error) => {
      normalizeAndPresentError(error, { context: 'useShotCreation', toastTitle: 'Failed to create shot with generations' });
    },
  });
};

export const useHandleExternalImageDrop = () => {
  const createShotMutation = useCreateShot();
  const addImageToShotMutation = useAddImageToShot();

  return useMutation({
    mutationFn: async (variables: ExternalImageDropVariables) => {
      const { currentProjectQueryKey } = variables;
      if (!currentProjectQueryKey) {
        toast.error('Cannot add image(s): current project is not identified.');
        return null;
      }

      try {
        return await processDroppedImages({
          variables,
          projectId: currentProjectQueryKey,
          createShot: createShotMutation.mutateAsync,
          addImageToShot: addImageToShotMutation.mutateAsync,
          addImageToShotWithoutPosition: addImageToShotMutation.mutateAsyncWithoutPosition,
        });
      } catch (error) {
        normalizeAndPresentError(error, { context: 'useShotCreation', toastTitle: 'Failed to process dropped image(s)' });
        return null;
      }
    },
  });
};

